SELECT 
FROM t_study_record
WHERE user_id = #{userId}
ORDER BY create_time DESC

    LIMIT #{limit}

SELECT 
FROM t_study_record
WHERE user_id = #{userId} 
AND DATE(create_time) = #{date}
ORDER BY create_time DESC

SELECT 
FROM t_study_record
WHERE user_id = #{userId} AND record_type = #{recordType}
ORDER BY create_time DESC

    LIMIT #{limit}
